import subprocess

def test_fizzbuzz_output(capsys):
    # Run the fizzbuzz script and capture its output
    result = subprocess.run(['python', 'fizzbuzz.py'], capture_output=True, text=True)
    output = result.stdout.strip().split('\n')
    expected = []
    for i in range(1, 101):
        if i % 15 == 0:
            expected.append('FizzBuzz')
        elif i % 3 == 0:
            expected.append('Fizz')
        elif i % 5 == 0:
            expected.append('Buzz')
        else:
            expected.append(str(i))
    assert output == expected
